import requests

# Example API call to generate an image using the gemini-2.5-flash-image model
API_KEY = "your_api_key_here"
API_URL = "https://api.platform.com/generate_image"

prompt = "A retro-styled illustration of a futuristic city at sunset"

headers = {
    "Authorization": f"Bearer {API_KEY}",
    "Content-Type": "application/json"
}

payload = {
    "model": "gemini-2.5-flash-image",
    "prompt": prompt,
    "options": {
        "style": "retro"  # Optional: aligns with the platform's default aesthetic
    }
}

response = requests.post(API_URL, json=payload, headers=headers)

if response.status_code == 200:
    image_data = response.json().get("image_url")
    print(f"Image generated successfully! URL: {image_data}")
else:
    print(f"Error generating image: {response.status_code} - {response.text}")
